<template>
  <div class="venice-map-wrapper" @mouseleave="hoveredSestiere = null">
    <svg
      viewBox="0 0 600 400"
      xmlns="http://www.w3.org/2000/svg"
      class="venice-map"
      :style="{ width: '100%', height: 'auto', maxWidth: '640px' }"
    >
      <defs>
        <filter id="glow">
          <feGaussianBlur stdDeviation="3" result="blur" />
          <feMerge>
            <feMergeNode in="blur" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>
      </defs>
      <g>
        <path
          v-for="s in sestieri"
          :key="s.code"
          :d="s.path"
          :fill="hoveredSestiere === s.code ? s.color + '35' : s.color + '12'"
          :stroke="hoveredSestiere === s.code ? s.color : s.color + '50'"
          :stroke-width="hoveredSestiere === s.code ? 2.5 : 1"
          :filter="hoveredSestiere === s.code ? 'url(#glow)' : 'none'"
          class="sestiere-path"
          @mouseenter="hoveredSestiere = s.code"
          @click="$emit('select', s.code)"
        />
      </g>

      <!-- Labels -->
      <text
        v-for="s in sestieri"
        :key="'label-' + s.code"
        :x="s.labelX"
        :y="s.labelY"
        text-anchor="middle"
        :fill="hoveredSestiere === s.code ? s.color : 'var(--dove-muted)'"
        :font-size="hoveredSestiere === s.code ? '11' : '9'"
        font-family="var(--font-venice)"
        class="sestiere-label"
        :opacity="hoveredSestiere === s.code ? 1 : 0.7"
        pointer-events="none"
      >
        {{ s.name }}
      </text>
    </svg>

    <!-- Hover info card -->
    <Transition name="fade">
      <div
        v-if="hoveredSestiere && hoveredInfo"
        class="map-tooltip glass rounded-xl px-4 py-3"
      >
        <span
          class="font-venice text-lg"
          :style="{ color: hoveredInfo.color }"
        >
          {{ hoveredInfo.name }}
        </span>
        <span class="text-xs block mt-0.5" :style="{ color: 'var(--dove-muted)' }">
          {{ hoveredInfo.range }}
        </span>
      </div>
    </Transition>
  </div>
</template>

